from threading import Lock


class AgentRegistry:
    """Thread-safe in-process agent registry."""

    def __init__(self, heartbeat_timeout: int = 60):
        self._cards: dict[str, AgentCard] = {}
        self._lock = Lock()
        self._heartbeat_timeout = heartbeat_timeout

    def register(self, card: AgentCard) -> str:
        """Add or update an agent card. Returns agent_id."""
        with self._lock:
            self._cards[card.agent_id] = card
        return card.agent_id

    def deregister(self, agent_id: str) -> bool:
        with self._lock:
            return bool(self._cards.pop(agent_id, None))

    def heartbeat(self, agent_id: str) -> bool:
        """Update the last-seen timestamp. Returns False if agent unknown."""
        with self._lock:
            card = self._cards.get(agent_id)
            if not card:
                return False
            card.heartbeat_at = datetime.now(timezone.utc).isoformat()
            return True

    def find_by_capability(self, capability: str) -> list[AgentCard]:
        """Return healthy agents that have the requested capability."""
        from datetime import timedelta
        now = datetime.now(timezone.utc)
        cutoff = timedelta(seconds=self._heartbeat_timeout)
        with self._lock:
            return [
                c for c in self._cards.values()
                if capability in c.capabilities
                and c.healthy
                and (now - datetime.fromisoformat(c.heartbeat_at)) < cutoff
            ]

    def find_by_protocol(self, protocol: str) -> list[AgentCard]:
        with self._lock:
            return [c for c in self._cards.values() if protocol in c.supported_protocols]

    def list_all(self) -> list[AgentCard]:
        with self._lock:
            return list(self._cards.values())


# Singleton shared across the process
registry = AgentRegistry(heartbeat_timeout=60)

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI(title="Agent Registry")
_reg = AgentRegistry()


class CardIn(BaseModel):
    name: str
    description: str
    endpoint: str
    capabilities: list[str]
    supported_protocols: list[str] = []
    metadata: dict = {}


@app.post("/agents", status_code=201)
def register(body: CardIn):
    card = AgentCard(
        name=body.name,
        description=body.description,
        endpoint=body.endpoint,
        capabilities=body.capabilities,
        supported_protocols=body.supported_protocols,
        metadata=body.metadata,
    )
    agent_id = _reg.register(card)
    return {"agent_id": agent_id}


@app.get("/agents")
def list_agents(capability: str | None = None, protocol: str | None = None):
    if capability:
        return _reg.find_by_capability(capability)
    if protocol:
        return _reg.find_by_protocol(protocol)
    return _reg.list_all()


@app.get("/agents/{agent_id}")
def get_agent(agent_id: str):
    cards = _reg.list_all()
    card = next((c for c in cards if c.agent_id == agent_id), None)
    if not card:
        raise HTTPException(404, f"Agent {agent_id!r} not found")
    return card


@app.post("/agents/{agent_id}/heartbeat")
def heartbeat(agent_id: str):
    ok = _reg.heartbeat(agent_id)
    if not ok:
        raise HTTPException(404, f"Agent {agent_id!r} not found")
    return {"ok": True}


@app.delete("/agents/{agent_id}")
def deregister(agent_id: str):
    ok = _reg.deregister(agent_id)
    return {"removed": ok}

