def eviction_loop(reg: AgentRegistry, check_interval: int = 30):
    """Background thread: mark agents unhealthy after missed heartbeats."""
    while True:
        time.sleep(check_interval)
        now = datetime.now(timezone.utc)
        with reg._lock:
            for card in reg._cards.values():
                age = (now - datetime.fromisoformat(card.heartbeat_at)).total_seconds()
                card.healthy = age <= reg._heartbeat_timeout


# Start eviction in production
evict_thread = threading.Thread(target=eviction_loop, args=(registry,), daemon=True)
evict_thread.start()
